import{c as i,Z as e,Q as l,j as r,o,m as d}from"./chunks/framework.qjzPVSkb.js";const p=JSON.parse('{"title":"Kimi","description":"月之暗面出品——200 万字超长上下文国产 AI 助手","frontmatter":{"title":"Kimi","description":"月之暗面出品——200 万字超长上下文国产 AI 助手","difficulty":"beginner"},"headers":[],"relativePath":"tools/kimi.md","filePath":"tools/kimi.md"}'),n={name:"tools/kimi.md"};function h(s,a,c,u,m,b){const t=e("DifficultyBadge");return l(),r("div",null,[o(t,{level:"beginner"}),a[0]||(a[0]=d('<h1 id="kimi" tabindex="-1">Kimi <a class="header-anchor" href="#kimi" aria-label="Permalink to &quot;Kimi&quot;">​</a></h1><h2 id="一句话定位" tabindex="-1">一句话定位 <a class="header-anchor" href="#一句话定位" aria-label="Permalink to &quot;一句话定位&quot;">​</a></h2><p><strong>长上下文国产助手</strong>——200 万字上下文窗口，一键总结整本书不是梦，还支持强大的联网搜索。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>详情</th></tr></thead><tbody><tr><td>公司</td><td>月之暗面 (Moonshot AI)</td></tr><tr><td>价格</td><td>免费</td></tr><tr><td>主要模型</td><td>Kimi 最新模型</td></tr><tr><td>上下文窗口</td><td>200 万字（约 400K tokens）</td></tr><tr><td>首发时间</td><td>2023 年 10 月</td></tr></tbody></table><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><h3 id="📚-超长上下文-200-万字" tabindex="-1">📚 超长上下文（200 万字） <a class="header-anchor" href="#📚-超长上下文-200-万字" aria-label="Permalink to &quot;📚 超长上下文（200 万字）&quot;">​</a></h3><p>这是 Kimi 最突出的特点。你可以：</p><ul><li>上传一整本书，让它总结核心内容</li><li>上传几百页的 PDF 论文，逐章分析</li><li>上传法律合同，逐条审查风险条款</li><li>上传项目文档，对比多个版本差异</li></ul><h3 id="🌐-联网搜索" tabindex="-1">🌐 联网搜索 <a class="header-anchor" href="#🌐-联网搜索" aria-label="Permalink to &quot;🌐 联网搜索&quot;">​</a></h3><p>Kimi 的联网搜索能力非常强，可以搜索网页、公众号文章等中文互联网内容。搜索结果质量高，引用清晰。</p><h3 id="📄-文件处理" tabindex="-1">📄 文件处理 <a class="header-anchor" href="#📄-文件处理" aria-label="Permalink to &quot;📄 文件处理&quot;">​</a></h3><p>支持上传 TXT、PDF、Word、Excel、PPT、图片等多种格式。上传后可以直接针对文件内容提问。</p><h3 id="🔧-浏览器插件" tabindex="-1">🔧 浏览器插件 <a class="header-anchor" href="#🔧-浏览器插件" aria-label="Permalink to &quot;🔧 浏览器插件&quot;">​</a></h3><p>提供 Chrome/Edge 浏览器插件，可以在浏览网页时随时调用 Kimi 进行总结、翻译等。</p><h2 id="优势" tabindex="-1">优势 <a class="header-anchor" href="#优势" aria-label="Permalink to &quot;优势&quot;">​</a></h2><ul><li><strong>超长上下文</strong>：200 万字的处理能力在同类产品中名列前茅</li><li><strong>完全免费</strong>：目前没有任何付费计划，所有功能免费使用</li><li><strong>联网搜索</strong>：中文互联网搜索质量高，尤其适合需要查找国内信息</li><li><strong>中文友好</strong>：国产模型，中文理解和生成自然流畅</li><li><strong>无使用限制</strong>：免费版没有明显的次数限制</li></ul><h2 id="不足" tabindex="-1">不足 <a class="header-anchor" href="#不足" aria-label="Permalink to &quot;不足&quot;">​</a></h2><ul><li>不支持图像生成</li><li>API 生态不如 OpenAI 丰富</li><li>代码能力弱于 Claude 和 DeepSeek</li><li>复杂推理深度不如 Claude 3.5 Sonnet</li><li>不开源，无法私有化部署</li></ul><h2 id="适合谁" tabindex="-1">适合谁？ <a class="header-anchor" href="#适合谁" aria-label="Permalink to &quot;适合谁？&quot;">​</a></h2><ul><li>✅ 需要处理超长文档的用户</li><li>✅ 中文场景为主的用户</li><li>✅ 学生和研究人员（论文阅读、文献整理）</li><li>✅ 需要联网搜索国内信息的用户</li><li>✅ 预算为零的个人用户</li><li>⚠️ 需要高强度代码开发的用户建议搭配 Cursor 或 Claude</li></ul><h2 id="关联阅读" tabindex="-1">关联阅读 <a class="header-anchor" href="#关联阅读" aria-label="Permalink to &quot;关联阅读&quot;">​</a></h2><ul><li><a href="/ai-knowledge/terms/context-window.html">上下文窗口</a> —— 了解为什么上下文窗口很重要</li><li><a href="/ai-knowledge/practices/claude-analysis.html">用 Claude 分析文档</a> —— 另一款文档分析利器</li><li><a href="/ai-knowledge/terms/rag.html">RAG</a> —— 突破上下文限制的另一种思路</li></ul>',23))])}const k=i(n,[["render",h]]);export{p as __pageData,k as default};
